%[text] # Comparison
%[text] Direct comparison of static data for ψ = 0° and ψ = 45°.
clear; clc; close all hidden;
%%
%[text] ## Configuration
AXIS = 3; %[control:dropdown:7ac0]{"position":[8,9]}
ALIGNED_FOLDER = "/Users/alexwang/Documents/MATLAB/Linear Traverse/Data/2025_08_15_Y0_STAT"; %[control:filebrowser:879a]{"position":[18,92]}
ROTATED_FOLDER = "/Users/alexwang/Documents/MATLAB/Linear Traverse/Data/2025_08_15_Y15_STAT"; %[control:filebrowser:0186]{"position":[18,93]}
OUT_FOLDER = "/Users/alexwang/Downloads"; %[control:filebrowser:2fa5]{"position":[14,41]}
MAX = 1; %[control:slider:32c3]{"position":[7,8]}
ERRORBAR = true; %[control:checkbox:3bbe]{"position":[12,16]}
CF_VOLTAGE = 4;
%%
name = Config.NAMES(AXIS);
conv = dictionary(Config.NAMES, ["F_y" "F_x" "F_z" "M_y" "M_x" "M_z"]);
disp_name = conv(name);

out_folder = fullfile(OUT_FOLDER, strjoin(["comparison", "stacked", disp_name], "-"));

if ~exist(out_folder, "dir")
    mkdir(out_folder);
end
%%
%[text] ## FT Comparison
%[text] Plot chosen axis versus distance.
if AXIS <= 3
    DENOMINATOR = Config.W * MAX;
    Process.format_plot("", "Separation, $\Delta z/l$", "Force, $\bar{" + disp_name + "}/W$"); %[output:4f8b01cc]
else
    DENOMINATOR = Config.W * Config.L * MAX;
    Process.format_plot("", "Separation, $\Delta z/l$", "Moment, $\bar{" + disp_name + "}/(Wl)$");
end

xlim([0 17]); %[output:4f8b01cc]
ylim([0.3 0.9]); %[output:4f8b01cc]
set(gcf, 'Position', [100 100 750 750]); %[output:4f8b01cc]

%% Aligned

load(fullfile(ALIGNED_FOLDER, 'processed_data'), 'results');
SDS = results.(name).SD / (Config.L / 1000);
static = table2array(results.(name)(:, 2:end)) / DENOMINATOR;

if ERRORBAR == true
    % Plot results (error bars)
    h1 = errorbar(SDS, mean(static, 2), std(static, 0, 2), 'bo', 'LineWidth', 1.5); %[output:4f8b01cc]
else
    % Plot results (data)
    h1 = plot(SDS, static, "bx", "MarkerSize", 8, "LineWidth", 1.5);
end

%% Rotated

load(fullfile(ROTATED_FOLDER, 'processed_data'), 'results');
SDS = results.(name).SD / (Config.L / 1000);
static = table2array(results.(name)(:, 2:end)) / DENOMINATOR;

if ERRORBAR == true
    % Plot results (error bars)
    h2 = errorbar(SDS, mean(static, 2), std(static, 0, 2), 'ro', 'LineWidth', 1.5); %[output:4f8b01cc]
else
    % Plot results (data)
    h2 = plot(SDS, static, "rx", "MarkerSize", 8, "LineWidth", 1.5);
end

legend([h1(1) h2(1)], ["Aligned" "Rotated"], 'Location', 'best'); %[output:4f8b01cc]

%% Save
exportgraphics(gca, fullfile(out_folder, "FT.svg"), 'ContentType', 'vector'); %[output:4f8b01cc]
savefig(gcf, fullfile(out_folder, "FT.fig"));
%%
%[text] ## Crazyflie Power
figure; %[output:2fa96387]
Process.format_plot("", "Separation, $\Delta z/l$", "Power, W"); %[output:2fa96387]

xlim([0 17]); %[output:2fa96387]
ylim([5 10]); %[output:2fa96387]
set(gcf, 'Renderer', 'painters', 'Position', [100 100 750 750]); %[output:2fa96387]

load(fullfile(ALIGNED_FOLDER, 'processed_data'), 'results');
SDS = results.(name).SD / (Config.L / 1000);
current = table2array(results.Current(:, 2:end));
power = current * CF_VOLTAGE;

if ERRORBAR == true
    % Plot results (error bars)
    h1 = errorbar(SDS, mean(power, 2), std(power, 0, 2), 'bo', 'LineWidth', 1.5); %[output:2fa96387]
else
    % Plot results (data)
    h1 = plot(SDS, power, "bx", "MarkerSize", 8, "LineWidth", 1.5);
end

load(fullfile(ROTATED_FOLDER, 'processed_data'), 'results');
SDS = results.(name).SD / (Config.L / 1000);
current = table2array(results.Current(:, 2:end));
power = current * CF_VOLTAGE;

if ERRORBAR == true
    % Plot results (error bars)
    h2 = errorbar(SDS, mean(power, 2), std(power, 0, 2), 'ro', 'LineWidth', 1.5); %[output:2fa96387]
else
    % Plot results (data)
    h2 = plot(SDS, power, "rx", "MarkerSize", 8, "LineWidth", 1.5);
end

legend([h1(1) h2(1)], ["Aligned" "Rotated"]); %[output:2fa96387]

%% Save
exportgraphics(gca, fullfile(out_folder, "power.svg"), 'ContentType', 'vector'); %[output:2fa96387]
savefig(gcf, fullfile(out_folder, "power.fig"));
%%
%[text] ## Peak Frequencies
figure %[output:2314269f]
Process.format_plot("", "Separation, $\Delta z/l$", "Rotation Speed, Hz"); %[output:2314269f]

xlim([0 17]); %[output:2314269f]
set(gcf, 'Renderer', 'painters', 'Position', [100 100 750 750]); %[output:2314269f]

% Aligned
load(fullfile(ALIGNED_FOLDER, 'processed_data'), 'results');
SDS = results.(name).SD / (Config.L / 1000);
transducer = table2array(results.("Transducer RPS")(:, 2:end));
traverse = table2array(results.("Traverse RPS")(:, 2:end)); %[output:69c2db5c]

scatter(SDS, median(transducer, 2), "bo", "filled");
scatter(SDS, median(traverse, 2), "bx", "LineWidth", 1.5);

% Rotated
load(fullfile(ROTATED_FOLDER, 'processed_data'), 'results');
SDS = results.(name).SD / (Config.L / 1000);
transducer = table2array(results.("Transducer RPS")(:, 2:end));
traverse = table2array(results.("Traverse RPS")(:, 2:end));

scatter(SDS, median(transducer, 2), "ro", "filled");
scatter(SDS, median(traverse, 2), "rx", "LineWidth", 1.5);

legend(["Aligned Transducer" "Aligned Traverse" "Rotated Transducer" "Rotated Traverse"]);

%% Save
exportgraphics(gca, fullfile(out_folder, "frequency.svg"), 'ContentType', 'vector');
savefig(gcf, fullfile(out_folder, "frequency.fig"));

